static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvTransposed2dAsymmetricInputAsymmetricKernelStridedGroupedPaddedDilatedCustomTilingData tiling;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const std::vector<int64_t> *stride = attrs->GetAttrPointer<std::vector<int64_t>>(0);
    const std::vector<int64_t> *padding = attrs->GetAttrPointer<std::vector<int64_t>>(1);
    const std::vector<int64_t> *output_padding = attrs->GetAttrPointer<std::vector<int64_t>>(2);
    const int64_t *groups = attrs->GetAttrPointer<int64_t>(3);
    const std::vector<int64_t> *dilation = attrs->GetAttrPointer<std::vector<int64_t>>(4);

    // Input shapes
    auto inShape = context->GetInputShape(0)->GetOriginShape();
    auto wShape = context->GetInputShape(1)->GetOriginShape();

    uint32_t batch   = inShape.GetDim(0);
    uint32_t inC     = inShape.GetDim(1);
    uint32_t inH     = inShape.GetDim(2);
    uint32_t inW     = inShape.GetDim(3);

    uint32_t outC_per_group = wShape.GetDim(1);  // weight (inC, outC/groups, kH, kW)
    uint32_t outC = outC_per_group * (*groups);
    uint32_t kH = wShape.GetDim(2);
    uint32_t kW = wShape.GetDim(3);

    uint32_t strideH = (uint32_t)(*stride)[0];
    uint32_t strideW = (uint32_t)(*stride)[1];
    uint32_t padH    = (uint32_t)(*padding)[0];
    uint32_t padW    = (uint32_t)(*padding)[1];
    uint32_t outPadH = (uint32_t)(*output_padding)[0];
    uint32_t outPadW = (uint32_t)(*output_padding)[1];
    uint32_t dilH    = (uint32_t)(*dilation)[0];
    uint32_t dilW    = (uint32_t)(*dilation)[1];
    uint32_t grp     = (uint32_t)(*groups);

    // Compute output spatial dimensions (standard formula)
    uint32_t outH = (inH - 1) * strideH - 2 * padH + dilH * (kH - 1) + outPadH + 1;
    uint32_t outW = (inW - 1) * strideW - 2 * padW + dilW * (kW - 1) + outPadW + 1;

    // Tiling: conservative tile on output channels and spatial.
    uint32_t maxOutChunk = UB_BUDGET_BYTES / (4 * (1 + kH*kW));  // output floats per channel + weight
    if (maxOutChunk < 64) maxOutChunk = 64;
    uint32_t tileCOut = std::min(outC, maxOutChunk / (outH * outW / 4 + 1));
    if (tileCOut == 0) tileCOut = 1;
    uint32_t tileHOut = std::min(outH, 8u);
    uint32_t tileWOut = std::min(outW, 8u);
    uint32_t inputPerTile = (inC / grp) * kH * kW;
    while (tileCOut * tileHOut * tileWOut + inputPerTile > UB_BUDGET_BYTES / 4) {
        if (tileWOut > 1) tileWOut /= 2;
        else if (tileHOut > 1) tileHOut /= 2;
        else if (tileCOut > 1) tileCOut /= 2;
        else break;
    }

    uint32_t numTilesPerBatch = CeilDiv(outC, tileCOut) * CeilDiv(outH, tileHOut) * CeilDiv(outW, tileWOut);
    uint32_t blockDim = batch * numTilesPerBatch;
